import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    for i in range(n):
        if (a[i] % 2) != ((i + 1) % 2):
            print(-1)
            return

    ops = []

    def rev(p):
        ops.append(p)
        a[:p] = a[:p][::-1]

    def bring_to_front(val, limit):
        pos = a.index(val)
        if pos == 0:
            return
        p = pos + 1
        if p % 2 == 1:
            rev(p)
        else:
            if p - 1 >= 1:
                rev(p - 1)
            pos2 = a.index(val)
            p2 = pos2 + 1
            if p2 % 2 == 0:
                rev(p2 + 1)
            else:
                rev(p2)

    m = n
    while m >= 3:
        bring_to_front(m, m)
        rev(m)
        if m >= 3:
            bring_to_front(m - 1, m - 1)
            pos_s = a.index(m - 1)
            if pos_s != m - 2:
                p = pos_s + 1
                if p % 2 == 0:
                    if p > 1:
                        rev(p - 1)
                    rev(p + 1 if (p+1) <= m-1 else p-1)
                if a.index(m-1) == 0:
                    rev(m - 2)
        m -= 2

    if a == list(range(1, n + 1)):
        print(len(ops))
        if ops:
            print(*ops)
        else:
            print()
    else:
        print(-1)

t = int(input())
for _ in range(t):
    solve()

